class IncrementalStack:
    def __init__(self):
        self.stack = []

    def push(self, val):
        self.stack.append(val)

    def pop(self):
        if not self.is_empty():
            return self.stack.pop()
        else:
            return None

    def peek(self):
        if not self.is_empty():
            return self.stack[-1]
        else:
            return None

    def is_empty(self):
        return len(self.stack) == 0

    def size(self):
        return len(self.stack)

    def increment(self, k, val):
        if k > len(self.stack):
            for i in range(len(self.stack)):
                self.stack[i] += val
        else:
            for i in range(k):
                self.stack[i] += val

if __name__ == '__main__':
    stack = IncrementalStack()
    stack.push(1)
    stack.push(2)
    stack.push(3)

    print("Initial stack:", stack.stack)

    stack.increment(2, 10)
    print("Stack after increment(2, 10):", stack.stack)

    stack.increment(3, 5)
    print("Stack after increment(3, 5):", stack.stack)

    print("Popped:", stack.pop())
    print("Stack after pop:", stack.stack)

    print("Peek:", stack.peek())
